import React, { useState, useRef, useEffect } from "react";
import {
  StyleSheet,
  Text,
  View,
  ScrollView,
  Pressable,
  Platform,
  Dimensions,
  ActivityIndicator,
} from "react-native";
import { router } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Ionicons, MaterialCommunityIcons } from "@expo/vector-icons";
import { LinearGradient } from "expo-linear-gradient";
import * as Haptics from "expo-haptics";
import Animated, { FadeInDown } from "react-native-reanimated";
import { useTheme } from "@/lib/useTheme";
import { getOttApps } from "@/lib/admin-storage";
import type { OttApp } from "@/lib/admin-storage";
import { cardShadow } from "@/lib/shadows";
import { Settings } from "@/lib/firestore";

const { width } = Dimensions.get("window");
const CARD_W = (width - 56) / 2;

const CATEGORIES = [
  { key: "popular", label: "Popular", icon: "flame-outline" as const },
  { key: "business", label: "Business Growth", icon: "trending-up-outline" as const },
  { key: "ott", label: "OTT Subscriptions", icon: "tv-outline" as const },
  { key: "offers", label: "Offers", icon: "pricetag-outline" as const },
];

const HOW_IT_WORKS = [
  { step: "01", title: "Choose Service", desc: "Browse our premium services", icon: "search-outline" as const, color: "#6366F1" },
  { step: "02", title: "Place Order", desc: "Complete your purchase securely", icon: "cart-outline" as const, color: "#0D9488" },
  { step: "03", title: "Team Connects", desc: "Our expert team reaches out", icon: "people-outline" as const, color: "#F59E0B" },
  { step: "04", title: "Delivered", desc: "Ready in 24–48 hours", icon: "checkmark-circle-outline" as const, color: "#10B981" },
];

const TRUST_BADGES = [
  { icon: "time-outline" as const, label: "Within 24hrs" },
  { icon: "shield-checkmark-outline" as const, label: "Secure Delivery" },
  { icon: "headset-outline" as const, label: "24/7 Support" },
];

export default function ServicesScreen() {
  const { colors, isDark } = useTheme();
  const insets = useSafeAreaInsets();
  const topPadding = Platform.OS === "web" ? 67 : insets.top;
  const [activeCategory, setActiveCategory] = useState("popular");
  const scrollRef = useRef<ScrollView>(null);
  const ottSectionY = useRef(0);
  const businessSectionY = useRef(0);
  const [ottApps, setOttApps] = useState<OttApp[]>([]);
  const [ottLoading, setOttLoading] = useState(true);
  const [metaPrice, setMetaPrice] = useState(499);
  const [metaOrigPrice, setMetaOrigPrice] = useState(699);

  useEffect(() => {
    getOttApps().then((a) => { setOttApps(a); setOttLoading(false); }).catch(() => setOttLoading(false));
    Settings.getMetaAdsPricing().then((p) => { setMetaPrice(p.weekly); setMetaOrigPrice(p.origWeekly); }).catch(() => {});
  }, []);

  function scrollToSection(key: string) {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    setActiveCategory(key);
    if (key === "ott" && scrollRef.current) {
      scrollRef.current.scrollTo({ y: ottSectionY.current - 80, animated: true });
    } else if ((key === "business" || key === "popular") && scrollRef.current) {
      scrollRef.current.scrollTo({ y: businessSectionY.current - 80, animated: true });
    } else if (key === "offers") {
      router.push("/subscriptions");
    }
  }

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <ScrollView
        ref={scrollRef}
        contentContainerStyle={[styles.scrollContent, { paddingTop: topPadding + 8 }]}
        showsVerticalScrollIndicator={false}
      >
        {/* HERO SECTION */}
        <Animated.View entering={FadeInDown.duration(600)}>
          <LinearGradient
            colors={isDark
              ? ["#0F172A", "#0D9488", "#065F46"]
              : ["#F0FDFA", "#CCFBF1", "#99F6E4"]
            }
            start={{ x: 0, y: 0 }}
            end={{ x: 1, y: 1 }}
            style={styles.heroGradient}
          >
            <View style={styles.heroContent}>
              <View style={[styles.heroPill, { backgroundColor: isDark ? "rgba(13,148,136,0.3)" : "rgba(13,148,136,0.15)" }]}>
                <Ionicons name="sparkles" size={12} color={colors.tint} />
                <Text style={[styles.heroPillText, { color: colors.tint }]}>Premium Services</Text>
              </View>
              <Text style={[styles.heroTitle, { color: isDark ? "#F8FAFC" : "#0F172A" }]}>
                Grow Faster.{"\n"}Save More.
              </Text>
              <Text style={[styles.heroSubtitle, { color: isDark ? "#94A3B8" : "#475569" }]}>
                Marketing, subscriptions, and digital services — all in one powerful platform.
              </Text>
              <View style={styles.heroTrustRow}>
                {[
                  { label: "Secure Payments", icon: "shield-checkmark" as const },
                  { label: "Verified Services", icon: "checkmark-circle" as const },
                  { label: "24/7 Support", icon: "headset" as const },
                ].map((t) => (
                  <View key={t.label} style={styles.heroTrustItem}>
                    <Ionicons name={t.icon} size={13} color={isDark ? "#34D399" : "#059669"} />
                    <Text style={[styles.heroTrustText, { color: isDark ? "#A7F3D0" : "#047857" }]}>{t.label}</Text>
                  </View>
                ))}
              </View>
              <View style={styles.heroBtnRow}>
                <Pressable
                  style={({ pressed }) => [{ opacity: pressed ? 0.9 : 1 }]}
                  onPress={() => {
                    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
                    scrollRef.current?.scrollTo({ y: businessSectionY.current - 80, animated: true });
                  }}
                >
                  <View style={styles.heroBtnGlow}>
                    <LinearGradient
                      colors={["#0D9488", "#14B8A6"]}
                      start={{ x: 0, y: 0 }}
                      end={{ x: 1, y: 0 }}
                      style={styles.heroBtnPrimary}
                    >
                      <Ionicons name="rocket-outline" size={16} color="#FFF" />
                      <Text style={styles.heroBtnPrimaryText}>Explore Services</Text>
                    </LinearGradient>
                  </View>
                </Pressable>
                <Pressable
                  style={({ pressed }) => [
                    styles.heroBtnSecondary,
                    {
                      backgroundColor: isDark ? "rgba(255,255,255,0.15)" : "rgba(13,148,136,0.08)",
                      borderColor: isDark ? "rgba(255,255,255,0.25)" : "rgba(13,148,136,0.2)",
                      opacity: pressed ? 0.8 : 1,
                    },
                  ]}
                  onPress={() => {
                    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
                    router.push("/subscriptions");
                  }}
                >
                  <Ionicons name="pricetag-outline" size={14} color={isDark ? "#5EEAD4" : colors.tint} />
                  <Text style={[styles.heroBtnSecondaryText, { color: isDark ? "#5EEAD4" : colors.tint }]}>View Offers</Text>
                </Pressable>
              </View>
            </View>
          </LinearGradient>
        </Animated.View>

        {/* SOCIAL PROOF */}
        <Animated.View entering={FadeInDown.delay(100).duration(500)} style={styles.socialProofRow}>
          {[
            { value: "500+", label: "Campaigns", icon: "rocket-outline" as const, color: "#6366F1" },
            { value: "98%", label: "Success Rate", icon: "trophy-outline" as const, color: "#F59E0B" },
            { value: "24/7", label: "Support", icon: "headset-outline" as const, color: "#0D9488" },
          ].map((stat, i) => (
            <View
              key={stat.label}
              style={[
                styles.socialCard,
                {
                  backgroundColor: isDark ? "#111B2E" : "#FFFFFF",
                  borderColor: isDark ? "rgba(255,255,255,0.06)" : "#EEF2F6",
                },
                isDark ? cardShadow(colors.cardShadow) : cardShadow("rgba(0,0,0,0.04)", 5),
              ]}
            >
              <View style={[styles.socialIconBg, { backgroundColor: stat.color + "15" }]}>
                <Ionicons name={stat.icon} size={18} color={stat.color} />
              </View>
              <Text style={[styles.socialValue, { color: isDark ? colors.text : "#0F172A" }]}>{stat.value}</Text>
              <Text style={[styles.socialLabel, { color: colors.textSecondary }]}>{stat.label}</Text>
            </View>
          ))}
        </Animated.View>

        {/* CATEGORY TABS */}
        <Animated.View entering={FadeInDown.delay(150).duration(500)}>
          <ScrollView
            horizontal
            showsHorizontalScrollIndicator={false}
            contentContainerStyle={styles.categoryScroll}
          >
            {CATEGORIES.map((cat) => {
              const isActive = activeCategory === cat.key;
              return (
                <Pressable
                  key={cat.key}
                  style={[
                    styles.categoryChip,
                    isActive
                      ? { backgroundColor: colors.tint }
                      : { backgroundColor: isDark ? "#1E293B" : "#F1F5F9", borderColor: isDark ? "#334155" : "#E2E8F0", borderWidth: 1 },
                  ]}
                  onPress={() => scrollToSection(cat.key)}
                >
                  <Ionicons name={cat.icon} size={14} color={isActive ? "#FFF" : colors.textSecondary} />
                  <Text style={[styles.categoryChipText, { color: isActive ? "#FFF" : colors.text }]}>{cat.label}</Text>
                </Pressable>
              );
            })}
          </ScrollView>
        </Animated.View>

        {/* BUSINESS SERVICES SECTION */}
        <Animated.View
          entering={FadeInDown.delay(200).duration(500)}
          onLayout={(e) => { businessSectionY.current = e.nativeEvent.layout.y; }}
        >
          <View style={styles.sectionHeader}>
            <View style={styles.sectionTitleRow}>
              <View style={[styles.sectionLine, { backgroundColor: colors.tint }]} />
              <Text style={[styles.sectionTitle, { color: isDark ? colors.text : "#0F172A" }]}>Business Services</Text>
            </View>
            <View style={[styles.sectionBadge, { backgroundColor: "#EF444415" }]}>
              <Ionicons name="flame" size={12} color="#EF4444" />
              <Text style={[styles.sectionBadgeText, { color: "#EF4444" }]}>Hot</Text>
            </View>
          </View>

          <Pressable
            style={({ pressed }) => [{ opacity: pressed ? 0.97 : 1 }]}
            onPress={() => {
              Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
              router.push("/meta-ads-category");
            }}
          >
            <LinearGradient
              colors={isDark ? ["#0D9488", "#0F766E", "#115E59"] : ["#14B8A6", "#0D9488", "#0F766E"]}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 1 }}
              style={styles.metaCard}
            >
              <View style={styles.metaCardTop}>
                <View style={styles.metaIconRow}>
                  <View style={styles.metaIconCircle}>
                    <Ionicons name="logo-facebook" size={16} color="#FFF" />
                  </View>
                  <View style={styles.metaIconCircle}>
                    <Ionicons name="logo-instagram" size={16} color="#FFF" />
                  </View>
                </View>
                <View style={styles.metaBadgeRow}>
                  <View style={styles.metaBadge}>
                    <Ionicons name="star" size={10} color="#FCD34D" />
                    <Text style={styles.metaBadgeText}>4.9</Text>
                  </View>
                  <View style={[styles.metaBadge, { backgroundColor: "rgba(239,68,68,0.25)" }]}>
                    <Ionicons name="flame" size={10} color="#FB923C" />
                    <Text style={styles.metaBadgeText}>Most Popular</Text>
                  </View>
                </View>
              </View>

              <Text style={styles.metaTitle}>Meta Ads Setup</Text>
              <Text style={styles.metaDesc}>
                Get more leads, more sales, and grow your business with professional Facebook & Instagram ad campaigns managed by experts.
              </Text>

              <View style={styles.metaFeatures}>
                {[
                  { icon: "trending-up-outline" as const, label: "Campaign Setup" },
                  { icon: "people-outline" as const, label: "Audience Targeting" },
                  { icon: "color-palette-outline" as const, label: "Creative Design" },
                  { icon: "analytics-outline" as const, label: "Performance Reports" },
                ].map((f) => (
                  <View key={f.label} style={styles.metaFeatureChip}>
                    <Ionicons name={f.icon} size={13} color="#FFF" />
                    <Text style={styles.metaFeatureText}>{f.label}</Text>
                  </View>
                ))}
              </View>

              <View style={styles.metaBottom}>
                <View>
                  <Text style={styles.metaStarting}>Starting from</Text>
                  <Text style={{ fontSize: 13, fontFamily: "Inter_500Medium", color: "#94A3B8", textDecorationLine: "line-through" }}>₹{metaOrigPrice}/week</Text>
                  <Text style={styles.metaPrice}>
                    ₹{metaPrice}<Text style={styles.metaPriceSuffix}>/week</Text>
                  </Text>
                </View>
                <View style={styles.metaCta}>
                  <Text style={styles.metaCtaText}>View Plans</Text>
                  <Ionicons name="arrow-forward" size={16} color="#FFF" />
                </View>
              </View>
            </LinearGradient>
          </Pressable>

          <View style={styles.metaTrustRow}>
            {[
              { icon: "shield-checkmark-outline" as const, text: "Money Back Guarantee" },
              { icon: "time-outline" as const, text: "Within 24hrs" },
              { icon: "chatbubble-ellipses-outline" as const, text: "Dedicated Manager" },
            ].map((t) => (
              <View key={t.text} style={[styles.metaTrustItem, { backgroundColor: isDark ? "#111B2E" : "#FFFFFF", borderColor: isDark ? "#1E293B" : "#EEF2F6" }, !isDark && cardShadow("rgba(0,0,0,0.04)", 5)]}>
                <Ionicons name={t.icon} size={14} color={colors.tint} />
                <Text style={[styles.metaTrustText, { color: colors.textSecondary }]}>{t.text}</Text>
              </View>
            ))}
          </View>
        </Animated.View>

        {/* OTT SUBSCRIPTIONS SECTION */}
        <Animated.View
          entering={FadeInDown.delay(300).duration(500)}
          onLayout={(e) => { ottSectionY.current = e.nativeEvent.layout.y; }}
        >
          <View style={styles.sectionHeader}>
            <View style={styles.sectionTitleRow}>
              <View style={[styles.sectionLine, { backgroundColor: "#F97316" }]} />
              <Text style={[styles.sectionTitle, { color: isDark ? colors.text : "#0F172A" }]}>OTT Subscriptions</Text>
            </View>
            <Pressable
              style={[styles.viewAllBtn, { backgroundColor: "#F9731612" }]}
              onPress={() => {
                Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
                router.push("/subscriptions");
              }}
            >
              <Text style={[styles.viewAllText, { color: "#F97316" }]}>View All</Text>
              <Ionicons name="chevron-forward" size={13} color="#F97316" />
            </Pressable>
          </View>
          <Text style={[styles.sectionSub, { color: colors.textSecondary }]}>
            Premium app subscriptions at the best prices in India
          </Text>

          <View style={styles.ottGrid}>
            {ottLoading ? (
              <View style={styles.ottLoadingWrap}>
                <ActivityIndicator size="small" color={colors.tint} />
              </View>
            ) : ottApps.length === 0 ? (
              <Text style={[styles.ottEmptyText, { color: colors.textSecondary }]}>No subscriptions available yet</Text>
            ) : (
              ottApps.slice(0, 4).map((app, index) => (
                <Pressable
                  key={app.id}
                  style={({ pressed }) => [
                    styles.ottCard,
                    {
                      backgroundColor: isDark ? "#111B2E" : "#FFFFFF",
                      borderColor: isDark ? "rgba(255,255,255,0.06)" : "#EEF2F6",
                      opacity: pressed ? 0.92 : 1,
                    },
                    isDark ? cardShadow(colors.cardShadow) : cardShadow("rgba(0,0,0,0.04)", 5),
                  ]}
                  onPress={() => {
                    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
                    router.push("/subscriptions");
                  }}
                >
                  {(app.stockCount ?? 0) <= 0 || app.outOfStock ? (
                    <View style={[styles.ottBestDeal, { backgroundColor: "#EF4444" }]}>
                      <Text style={styles.ottBestDealText}>OUT OF STOCK</Text>
                    </View>
                  ) : index === 0 ? (
                    <View style={styles.ottBestDeal}>
                      <Text style={styles.ottBestDealText}>BEST DEAL</Text>
                    </View>
                  ) : (app.stockCount ?? 0) <= 5 ? (
                    <View style={[styles.ottBestDeal, { backgroundColor: "#F59E0B" }]}>
                      <Text style={styles.ottBestDealText}>LOW STOCK</Text>
                    </View>
                  ) : null}
                  <View style={[styles.ottIconWrap, { backgroundColor: app.color + "12" }]}>
                    <MaterialCommunityIcons name={app.icon as any} size={28} color={app.color} />
                  </View>
                  <Text style={[styles.ottName, { color: colors.text }]} numberOfLines={1}>{app.name}</Text>
                  <Text style={[styles.ottDesc, { color: colors.textSecondary }]} numberOfLines={2}>{app.description}</Text>
                  <View style={styles.ottPriceRow}>
                    <Text style={[styles.ottPrice, { color: colors.tint }]}>₹{app.price}</Text>
                    <Text style={[styles.ottPeriod, { color: colors.textSecondary }]}>/mo</Text>
                  </View>
                </Pressable>
              ))
            )}
          </View>

          <View style={styles.trustRow}>
            {TRUST_BADGES.map((b) => (
              <View key={b.label} style={[styles.trustBadge, { backgroundColor: isDark ? "#111B2E" : "#FFFFFF", borderColor: isDark ? "#1E293B" : "#EEF2F6" }, !isDark && cardShadow("rgba(0,0,0,0.04)", 5)]}>
                <Ionicons name={b.icon} size={16} color={colors.tint} />
                <Text style={[styles.trustText, { color: colors.text }]}>{b.label}</Text>
              </View>
            ))}
          </View>
        </Animated.View>

        {/* HOW IT WORKS */}
        <Animated.View entering={FadeInDown.delay(350).duration(500)}>
          <View style={[styles.sectionHeader, { marginTop: 8 }]}>
            <View style={styles.sectionTitleRow}>
              <View style={[styles.sectionLine, { backgroundColor: "#6366F1" }]} />
              <Text style={[styles.sectionTitle, { color: isDark ? colors.text : "#0F172A" }]}>How It Works</Text>
            </View>
          </View>
          <Text style={[styles.sectionSub, { color: colors.textSecondary }]}>
            Simple process, fast delivery
          </Text>

          <View style={styles.stepsContainer}>
            {HOW_IT_WORKS.map((step, i) => (
              <View key={step.step} style={styles.stepRow}>
                <View style={styles.stepLeftCol}>
                  <View style={[styles.stepCircle, { backgroundColor: step.color + "15" }]}>
                    <Ionicons name={step.icon} size={20} color={step.color} />
                  </View>
                  {i < HOW_IT_WORKS.length - 1 && (
                    <View style={[styles.stepLine, { backgroundColor: isDark ? "#1E293B" : "#E2E8F0" }]} />
                  )}
                </View>
                <View style={[styles.stepCard, { backgroundColor: isDark ? "#111B2E" : "#FFFFFF", borderColor: isDark ? "rgba(255,255,255,0.06)" : "#EEF2F6" }, isDark ? cardShadow(colors.cardShadow) : cardShadow("rgba(0,0,0,0.04)", 5)]}>
                  <Text style={[styles.stepNumber, { color: step.color }]}>{step.step}</Text>
                  <Text style={[styles.stepTitle, { color: colors.text }]}>{step.title}</Text>
                  <Text style={[styles.stepDesc, { color: colors.textSecondary }]}>{step.desc}</Text>
                </View>
              </View>
            ))}
          </View>
        </Animated.View>

        {/* CTA CHAT CARD */}
        <Animated.View entering={FadeInDown.delay(400).duration(500)}>
          <Pressable
            style={({ pressed }) => [{ opacity: pressed ? 0.95 : 1 }]}
            onPress={() => {
              Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
              router.push("/chat");
            }}
          >
            <LinearGradient
              colors={isDark ? ["#1E293B", "#0F172A"] : ["#F0FDFA", "#ECFDF5"]}
              start={{ x: 0, y: 0 }}
              end={{ x: 1, y: 1 }}
              style={[styles.ctaCard, { borderColor: isDark ? "#334155" : "#A7F3D0" }]}
            >
              <View style={[styles.ctaIcon, { backgroundColor: colors.tint + "18" }]}>
                <Ionicons name="chatbubbles" size={26} color={colors.tint} />
              </View>
              <Text style={[styles.ctaTitle, { color: colors.text }]}>Need help choosing?</Text>
              <Text style={[styles.ctaSub, { color: colors.textSecondary }]}>
                Chat with our experts for personalized recommendations
              </Text>
              <View style={[styles.ctaBtn, { backgroundColor: colors.tint }]}>
                <Ionicons name="chatbubble-ellipses-outline" size={16} color="#FFF" />
                <Text style={styles.ctaBtnText}>Start Chat</Text>
              </View>
            </LinearGradient>
          </Pressable>
        </Animated.View>

        <View style={{ height: 120 }} />
      </ScrollView>

      {/* FLOATING CHAT BUTTON */}
      <Pressable
        style={({ pressed }) => [
          styles.fab,
          { opacity: pressed ? 0.9 : 1 },
        ]}
        onPress={() => {
          Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
          router.push("/chat");
        }}
      >
        <LinearGradient
          colors={["#0D9488", "#14B8A6"]}
          style={styles.fabGradient}
        >
          <Ionicons name="chatbubble-ellipses" size={24} color="#FFF" />
        </LinearGradient>
      </Pressable>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  scrollContent: { paddingHorizontal: 20 },

  heroGradient: {
    borderRadius: 28,
    marginBottom: 20,
    overflow: "hidden",
  },
  heroContent: {
    padding: 24,
    paddingBottom: 28,
  },
  heroPill: {
    flexDirection: "row",
    alignItems: "center",
    alignSelf: "flex-start",
    gap: 6,
    paddingHorizontal: 14,
    paddingVertical: 7,
    borderRadius: 20,
    marginBottom: 18,
  },
  heroPillText: {
    fontSize: 12,
    fontFamily: "Inter_600SemiBold",
    letterSpacing: 0.3,
  },
  heroTitle: {
    fontSize: 36,
    fontFamily: "Inter_700Bold",
    lineHeight: 44,
    letterSpacing: -0.8,
    marginBottom: 10,
  },
  heroSubtitle: {
    fontSize: 14,
    fontFamily: "Inter_400Regular",
    lineHeight: 21,
    marginBottom: 14,
  },
  heroTrustRow: {
    flexDirection: "row",
    flexWrap: "wrap",
    gap: 12,
    marginBottom: 20,
  },
  heroTrustItem: {
    flexDirection: "row",
    alignItems: "center",
    gap: 5,
  },
  heroTrustText: {
    fontSize: 12,
    fontFamily: "Inter_500Medium",
  },
  heroBtnRow: {
    flexDirection: "row",
    alignItems: "center",
    flexWrap: "wrap",
    gap: 10,
  },
  heroBtnGlow: {
    borderRadius: 14,
    ...Platform.select({
      ios: {
        shadowColor: "#14B8A6",
        shadowOffset: { width: 0, height: 4 },
        shadowOpacity: 0.45,
        shadowRadius: 12,
      },
      android: { elevation: 8 },
      web: { boxShadow: "0 4px 20px rgba(20, 184, 166, 0.45)" } as any,
    }),
  },
  heroBtnPrimary: {
    flexDirection: "row",
    alignItems: "center",
    gap: 8,
