import React, { useState, useEffect } from "react";
import {
  StyleSheet,
  Text,
  View,
  TextInput,
  Pressable,
  Platform,
  KeyboardAvoidingView,
  ScrollView,
} from "react-native";
import { router } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { LinearGradient } from "expo-linear-gradient";
import * as Haptics from "expo-haptics";
import { useAdmin } from "@/lib/admin-context";
import { useTheme } from "@/lib/useTheme";

export default function AdminLoginScreen() {
  const { colors, isDark } = useTheme();
  const insets = useSafeAreaInsets();
  const { adminLogin, isAdmin } = useAdmin();
  const topPadding = Platform.OS === "web" ? 67 : insets.top;

  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");

  useEffect(() => {
    if (isAdmin) router.replace("/admin-dashboard");
  }, [isAdmin]);

  function handleLogin() {
    setError("");
    if (!password.trim()) {
      setError("Please enter the admin password");
      return;
    }
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    const success = adminLogin(password);
    if (success) {
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
      router.replace("/admin-dashboard");
    } else {
      setError("Invalid admin password");
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
    }
  }

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <LinearGradient
        colors={isDark ? ["#1E293B", "#0A1628"] : ["#F1F5F9", "#F8FAFC"]}
        style={[styles.gradient, { paddingTop: topPadding }]}
      >
        <Pressable
          style={styles.backButton}
          onPress={() => router.back()}
          hitSlop={12}
        >
          <Ionicons name="arrow-back" size={24} color={colors.text} />
        </Pressable>

        <KeyboardAvoidingView
          style={{ flex: 1 }}
          behavior={Platform.OS === "ios" ? "padding" : "height"}
          keyboardVerticalOffset={Platform.OS === "ios" ? 0 : 20}
        >
          <ScrollView
            contentContainerStyle={styles.scrollContent}
            keyboardShouldPersistTaps="handled"
            showsVerticalScrollIndicator={false}
            bounces={false}
          >
            <View style={styles.content}>
              <View style={[styles.iconContainer, { backgroundColor: colors.accent + "20" }]}>
                <Ionicons name="shield-checkmark" size={36} color={colors.accent} />
              </View>
              <Text style={[styles.title, { color: colors.text }]}>Admin Access</Text>
              <Text style={[styles.subtitle, { color: colors.textSecondary }]}>
                Enter the admin password to continue
              </Text>

              <View style={[styles.inputWrapper, { backgroundColor: colors.inputBg, borderColor: colors.border }]}>
                <Ionicons name="key-outline" size={20} color={colors.placeholder} />
                <TextInput
                  style={[styles.input, { color: colors.text }]}
                  placeholder="Admin password"
                  placeholderTextColor={colors.placeholder}
                  value={password}
                  onChangeText={setPassword}
                  secureTextEntry={!showPassword}
                  autoCapitalize="none"
                  autoCorrect={false}
                  onSubmitEditing={handleLogin}
                  returnKeyType="go"
                />
                <Pressable onPress={() => setShowPassword(!showPassword)} hitSlop={12}>
                  <Ionicons
                    name={showPassword ? "eye-off-outline" : "eye-outline"}
                    size={20}
                    color={colors.placeholder}
                  />
                </Pressable>
              </View>

              {!!error && (
                <View style={[styles.errorBox, { backgroundColor: colors.error + "15" }]}>
                  <Ionicons name="alert-circle" size={16} color={colors.error} />
                  <Text style={[styles.errorText, { color: colors.error }]}>{error}</Text>
                </View>
              )}

              <Pressable
                style={({ pressed }) => [
                  styles.loginButton,
                  { backgroundColor: colors.accent, opacity: pressed ? 0.9 : 1 },
                ]}
                onPress={handleLogin}
              >
                <Ionicons name="log-in-outline" size={20} color="#FFFFFF" />
                <Text style={styles.loginText}>Access Dashboard</Text>
              </Pressable>
            </View>
          </ScrollView>
        </KeyboardAvoidingView>
      </LinearGradient>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
