import { sql } from "drizzle-orm";
import { pgTable, text, varchar } from "drizzle-orm/pg-core";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

export const users = pgTable("users", {
  id: varchar("id")
    .primaryKey()
    .default(sql`gen_random_uuid()`),
  username: text("username").notNull().unique(),
  password: text("password").notNull(),
});

export const insertUserSchema = createInsertSchema(users).pick({
  username: true,
  password: true,
});

export type InsertUser = z.infer<typeof insertUserSchema>;
export type User = typeof users.$inferSelect;

lib/shadows.ts.content:
import { Platform, type ViewStyle } from "react-native";

export function cardShadow(shadowColor: string = "rgba(0,0,0,0.08)", elevation: number = 3): ViewStyle {
  if (Platform.OS === "web") {
    const y = Math.max(1, Math.round(elevation * 0.7));
    const blur = elevation * 3;
    return { boxShadow: `0 ${y}px ${blur}px ${shadowColor}` } as ViewStyle;
  }
  return {
    shadowColor,
    shadowOffset: { width: 0, height: Math.max(1, Math.round(elevation * 0.7)) },
    shadowOpacity: 1,
    shadowRadius: elevation * 2,
    elevation,
  };
}

export function elevatedShadow(shadowColor: string = "rgba(0,0,0,0.12)", elevation: number = 5): ViewStyle {
  if (Platform.OS === "web") {
    const y = Math.max(2, Math.round(elevation * 0.8));
    const blur = elevation * 3;
    return { boxShadow: `0 ${y}px ${blur}px ${shadowColor}` } as ViewStyle;
  }
  return {
    shadowColor,
    shadowOffset: { width: 0, height: Math.max(2, Math.round(elevation * 0.8)) },
    shadowOpacity: 1,
    shadowRadius: elevation * 2.5,
    elevation,
  };
}

app/auth.tsx.content:
import React, { useState, useRef } from "react";
import {
  StyleSheet,
  Text,
  View,
  TextInput,
  Pressable,
  ActivityIndicator,
  KeyboardAvoidingView,
  Platform,
  ScrollView,
  Animated,
  Dimensions,
} from "react-native";
import { router } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { LinearGradient } from "expo-linear-gradient";
import * as Haptics from "expo-haptics";
import { useAuth } from "@/lib/auth-context";
import { useTheme } from "@/lib/useTheme";
import { elevatedShadow } from "@/lib/shadows";

const { width } = Dimensions.get("window");

export default function AuthScreen() {
  const { colors, isDark } = useTheme();
  const insets = useSafeAreaInsets();
  const { login, signup } = useAuth();

  const [activeTab, setActiveTab] = useState<"login" | "signup">("login");
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [phone, setPhone] = useState("");
  const [identifier, setIdentifier] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [referralCode, setReferralCode] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const slideAnim = useRef(new Animated.Value(0)).current;

  function switchTab(tab: "login" | "signup") {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    Animated.spring(slideAnim, {
      toValue: tab === "login" ? 0 : 1,
      useNativeDriver: Platform.OS !== "web",
      tension: 80,
      friction: 12,
    }).start();
    setActiveTab(tab);
    setError("");
  }

  function validate(): boolean {
    if (activeTab === "login") {
      if (!identifier.trim()) {
        setError("Please enter your email or phone number");
        return false;
      }
      if (!password.trim() || password.length < 6) {
        setError("Password must be at least 6 characters");
        return false;
      }
    } else {
      if (!name.trim()) {
        setError("Please enter your name");
        return false;
      }
      if (!email.trim()) {
        setError("Please enter your email");
        return false;
      }
      if (!/\S+@\S+\.\S+/.test(email.trim())) {
        setError("Please enter a valid email");
        return false;
      }
      if (!phone.trim()) {
        setError("Please enter your phone number");
        return false;
      }
      if (!/^\d{10,}$/.test(phone.trim().replace(/[^0-9]/g, ""))) {
        setError("Please enter a valid phone number (min 10 digits)");
        return false;
      }
      if (!password.trim() || password.length < 6) {
        setError("Password must be at least 6 characters");
        return false;
      }
    }
    return true;
  }

  async function handleSubmit() {
    setError("");
    if (!validate()) return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    setLoading(true);
    try {
      if (activeTab === "login") {
        await login(identifier.trim(), password);
      } else {
        await signup(name.trim(), email.trim(), phone.trim().replace(/[^0-9]/g, ""), password, referralCode.trim() || undefined);
      }
      router.replace("/(tabs)");
    } catch (e: any) {
      setError(e.message || "Something went wrong");
      Haptics.notificationAsync(Haptics.NotificationFeedbackType.Error);
    } finally {
      setLoading(false);
    }
  }

  const tabIndicatorX = slideAnim.interpolate({
    inputRange: [0, 1],
    outputRange: [0, (width - 64) / 2],
  });

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <LinearGradient
        colors={isDark ? ["#0D9488", "#0A1628"] : ["#CCFBF1", "#F8FAFC"]}
        style={[styles.gradient, { paddingTop: insets.top + (Platform.OS === "web" ? 67 : 0) }]}
        start={{ x: 0, y: 0 }}
        end={{ x: 1, y: 1 }}
      >
        <KeyboardAvoidingView
          behavior={Platform.OS === "ios" ? "padding" : "height"}
          style={styles.keyboardView}
        >
          <ScrollView
            contentContainerStyle={styles.scrollContent}
            keyboardShouldPersistTaps="handled"
            showsVerticalScrollIndicator={false}
          >
            <View style={styles.logoSection}>
              <View style={[styles.logoContainer, { backgroundColor: colors.tint }]}>
                <Ionicons name="flash" size={32} color="#FFFFFF" />
              </View>
              <Text style={[styles.appName, { color: colors.text }]}>iDigitalZone</Text>
              <Text style={[styles.tagline, { color: colors.textSecondary }]}>
                Smart services for your digital growth
              </Text>
            </View>

            <View style={[styles.formCard, { backgroundColor: colors.surface }, elevatedShadow()]}>
              <View style={[styles.tabContainer, { backgroundColor: colors.surfaceSecondary }]}>
                <Animated.View
                  style={[
                    styles.tabIndicator,
                    { backgroundColor: colors.tint, transform: [{ translateX: tabIndicatorX }] },
                  ]}
                />
                <Pressable style={styles.tab} onPress={() => switchTab("login")}>
                  <Text
                    style={[
                      styles.tabText,
                      { color: activeTab === "login" ? "#FFFFFF" : colors.textSecondary },
                    ]}
                  >
                    Sign In
                  </Text>
                </Pressable>
                <Pressable style={styles.tab} onPress={() => switchTab("signup")}>
                  <Text
                    style={[
                      styles.tabText,
                      { color: activeTab === "signup" ? "#FFFFFF" : colors.textSecondary },
                    ]}
                  >
                    Sign Up
                  </Text>
                </Pressable>
              </View>

              {activeTab === "signup" && (
                <>
                  <View style={styles.inputGroup}>
                    <Text style={[styles.label, { color: colors.textSecondary }]}>Full Name</Text>
                    <View style={[styles.inputWrapper, { backgroundColor: colors.inputBg, borderColor: colors.border }]}>
                      <Ionicons name="person-outline" size={20} color={colors.placeholder} />
                      <TextInput
                        style={[styles.input, { color: colors.text }]}
                        placeholder="Your name"
                        placeholderTextColor={colors.placeholder}
                        value={name}
                        onChangeText={setName}
                        autoCapitalize="words"
                      />
                    </View>
                  </View>

                  <View style={styles.inputGroup}>
                    <Text style={[styles.label, { color: colors.textSecondary }]}>Email</Text>
                    <View style={[styles.inputWrapper, { backgroundColor: colors.inputBg, borderColor: colors.border }]}>
                      <Ionicons name="mail-outline" size={20} color={colors.placeholder} />
                      <TextInput
                        style={[styles.input, { color: colors.text }]}
                        placeholder="you@example.com"
                        placeholderTextColor={colors.placeholder}
                        value={email}
                        onChangeText={setEmail}
                        keyboardType="email-address"
                        autoCapitalize="none"
                        autoCorrect={false}
                      />
                    </View>
                  </View>

                  <View style={styles.inputGroup}>
                    <Text style={[styles.label, { color: colors.textSecondary }]}>Phone Number</Text>
                    <View style={[styles.inputWrapper, { backgroundColor: colors.inputBg, borderColor: colors.border }]}>
                      <Ionicons name="call-outline" size={20} color={colors.placeholder} />
                      <TextInput
                        style={[styles.input, { color: colors.text }]}
                        placeholder="9876543210"
                        placeholderTextColor={colors.placeholder}
                        value={phone}
                        onChangeText={setPhone}
                        keyboardType="phone-pad"
                      />
                    </View>
                  </View>

                  <View style={styles.inputGroup}>
                    <Text style={[styles.label, { color: colors.textSecondary }]}>Referral Code (Optional)</Text>
                    <View style={[styles.inputWrapper, { backgroundColor: colors.inputBg, borderColor: colors.border }]}>
                      <Ionicons name="gift-outline" size={20} color={colors.placeholder} />
                      <TextInput
                        style={[styles.input, { color: colors.text }]}
                        placeholder="e.g. NEXAB12CD"
                        placeholderTextColor={colors.placeholder}
                        value={referralCode}
                        onChangeText={(t) => setReferralCode(t.toUpperCase())}
                        autoCapitalize="characters"
                        autoCorrect={false}
                      />
                    </View>
                  </View>
                </>
              )}

              {activeTab === "login" && (
                <View style={styles.inputGroup}>
                  <Text style={[styles.label, { color: colors.textSecondary }]}>Email or Phone</Text>
                  <View style={[styles.inputWrapper, { backgroundColor: colors.inputBg, borderColor: colors.border }]}>
                    <Ionicons name="person-outline" size={20} color={colors.placeholder} />
                    <TextInput
                      style={[styles.input, { color: colors.text }]}
                      placeholder="Email or phone number"
                      placeholderTextColor={colors.placeholder}
                      value={identifier}
                      onChangeText={setIdentifier}
                      autoCapitalize="none"
                      autoCorrect={false}
                    />
                  </View>
                </View>
              )}

              <View style={styles.inputGroup}>
                <Text style={[styles.label, { color: colors.textSecondary }]}>Password</Text>
                <View style={[styles.inputWrapper, { backgroundColor: colors.inputBg, borderColor: colors.border }]}>
                  <Ionicons name="lock-closed-outline" size={20} color={colors.placeholder} />
                  <TextInput
                    style={[styles.input, { color: colors.text }]}
                    placeholder="Min. 6 characters"
                    placeholderTextColor={colors.placeholder}
                    value={password}
                    onChangeText={setPassword}
                    secureTextEntry={!showPassword}
                    autoCapitalize="none"
                  />
                  <Pressable onPress={() => setShowPassword(!showPassword)} hitSlop={12}>
                    <Ionicons
                      name={showPassword ? "eye-off-outline" : "eye-outline"}
                      size={20}
                      color={colors.placeholder}
                    />
                  </Pressable>
                </View>
              </View>

              {!!error && (
                <View style={[styles.errorBox, { backgroundColor: colors.error + "15" }]}>
                  <Ionicons name="alert-circle" size={16} color={colors.error} />
                  <Text style={[styles.errorText, { color: colors.error }]}>{error}</Text>
                </View>
              )}

              <Pressable
                style={({ pressed }) => [
                  styles.submitButton,
                  { backgroundColor: colors.tint, opacity: pressed ? 0.9 : 1 },
                ]}
                onPress={handleSubmit}
                disabled={loading}
              >
                {loading ? (
                  <ActivityIndicator color="#FFFFFF" />
                ) : (
                  <Text style={styles.submitText}>
                    {activeTab === "login" ? "Sign In" : "Create Account"}
                  </Text>
                )}
              </Pressable>

              {activeTab === "login" && (
                <Pressable style={styles.forgotButton}>
                  <Text style={[styles.forgotText, { color: colors.tint }]}>Forgot Password?</Text>
                </Pressable>
