import React, { useState, useEffect, useCallback } from "react";
import {
  StyleSheet,
  Text,
  View,
  ScrollView,
  Pressable,
  Alert,
  Platform,
  Linking,
  ActivityIndicator,
  Modal,
  RefreshControl,
} from "react-native";
import { router } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import * as Haptics from "expo-haptics";
import { useAuth } from "@/lib/auth-context";
import { useTheme } from "@/lib/useTheme";
import { Settings, Users } from "@/lib/firestore";
import type { UserProfile } from "@/lib/firestore";

export default function ProfileScreen() {
  const { colors, isDark, themeMode, setThemeMode } = useTheme();
  const insets = useSafeAreaInsets();
  const { user, logout, isAuthenticated, isLoading } = useAuth();
  const topPadding = Platform.OS === "web" ? 67 : insets.top;

  const [whatsappNumber, setWhatsappNumber] = useState("");
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [walletBalance, setWalletBalance] = useState(0);
  const [walletLoading, setWalletLoading] = useState(true);
  const [themeSheetVisible, setThemeSheetVisible] = useState(false);
  const [refreshing, setRefreshing] = useState(false);

  const loadProfileData = useCallback(async () => {
    if (!user) return;
    try {
      const [wp, prof] = await Promise.all([
        Settings.getWhatsAppNumber().catch(() => ""),
        Users.getById(user.id).catch(() => null),
      ]);
      setWhatsappNumber(wp);
      setProfile(prof);
      setWalletBalance(prof?.walletBalance || 0);
    } catch {} finally {
      setWalletLoading(false);
    }
  }, [user]);

  useEffect(() => { loadProfileData(); }, [loadProfileData]);

  const onRefresh = useCallback(async () => {
    setRefreshing(true);
    setWalletLoading(true);
    await loadProfileData();
    setRefreshing(false);
  }, [loadProfileData]);

  function handleWhatsApp() {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    if (!whatsappNumber) {
      Alert.alert("Not Available", "WhatsApp contact is not set up yet.");
      return;
    }
    Linking.openURL(`https://wa.me/${whatsappNumber.replace(/[^0-9]/g, "")}`).catch(() => {
      Alert.alert("Error", "Could not open WhatsApp.");
    });
  }

  if (isLoading || !isAuthenticated) return null;

  function handleLogout() {
    Alert.alert("Sign Out", "Are you sure you want to sign out?", [
      { text: "Cancel", style: "cancel" },
      {
        text: "Sign Out",
        style: "destructive",
        onPress: async () => {
          Haptics.notificationAsync(Haptics.NotificationFeedbackType.Warning);
          await logout();
          router.replace("/auth");
        },
      },
    ]);
  }

  const initials = (user?.name || "U").charAt(0).toUpperCase();
  const themeLabel = themeMode === "system" ? "System" : themeMode === "dark" ? "Dark" : "Light";

  const accountItems = [
    { icon: "person-outline" as const, label: "Edit Profile", onPress: () => router.push("/edit-profile") },
    { icon: "bag-handle-outline" as const, label: "My Orders", onPress: () => router.push("/(tabs)/orders") },
    { icon: "diamond-outline" as const, label: "Subscriptions", onPress: () => router.push("/subscriptions") },
  ];

  const supportItems = [
    { icon: "logo-whatsapp" as const, label: "WhatsApp Contact", value: whatsappNumber ? `+${whatsappNumber}` : undefined, onPress: handleWhatsApp, iconColor: "#25D366", iconBg: "#25D36612" },
    {
      icon: "information-circle-outline" as const,
      label: "About iDigitalZone",
      value: "v1.0.0",
      isAbout: true,
      onPress: () => {},
    },
  ];

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <ScrollView
        contentContainerStyle={[styles.scroll, { paddingTop: topPadding + 12 }]}
        showsVerticalScrollIndicator={false}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={onRefresh}
            tintColor={colors.tint}
            colors={[colors.tint]}
          />
        }
      >
        <Pressable
          style={[styles.profileRow, { backgroundColor: colors.card, borderColor: colors.border }]}
          onPress={() => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light); router.push("/edit-profile"); }}
        >
          <View style={[styles.avatar, { backgroundColor: colors.tint }]}>
            <Text style={styles.avatarText}>{initials}</Text>
          </View>
          <View style={styles.profileInfo}>
            <Text style={[styles.profileName, { color: colors.text }]} numberOfLines={1}>{user?.name}</Text>
            <Text style={[styles.profileSub, { color: colors.textSecondary }]} numberOfLines={1}>{user?.email}</Text>
          </View>
          <Ionicons name="create-outline" size={16} color={colors.textSecondary} />
        </Pressable>

        <Pressable
          style={[styles.walletStrip, { backgroundColor: colors.card, borderColor: colors.border }]}
          onPress={() => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light); router.push("/wallet"); }}
        >
