            <View style={[styles.sheetHandle, { backgroundColor: colors.border }]} />
            <Text style={[styles.sheetTitle, { color: colors.text }]}>Appearance</Text>
            {([
              { key: "light" as const, label: "Light", icon: "sunny-outline" as const },
