import { router } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import { LinearGradient } from "expo-linear-gradient";
import * as Haptics from "expo-haptics";
import * as Clipboard from "expo-clipboard";
import { useAuth } from "@/lib/auth-context";
import { useTheme } from "@/lib/useTheme";
import { Users, Wallet, Referrals } from "@/lib/firestore";
import type { WalletTransaction, UserProfile } from "@/lib/firestore";

const REDEEM_PRESETS = [100, 200, 500, 1000];

export default function InviteEarnScreen() {
  const { colors, isDark } = useTheme();
  const insets = useSafeAreaInsets();
  const { user, isAuthenticated, isLoading } = useAuth();
  const topPadding = Platform.OS === "web" ? 67 : insets.top;

  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [walletCoins, setWalletCoins] = useState(0);
  const [transactions, setTransactions] = useState<WalletTransaction[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [codeCopied, setCodeCopied] = useState(false);
  const [redeemVisible, setRedeemVisible] = useState(false);
  const [redeemAmount, setRedeemAmount] = useState("");
  const [selectedPreset, setSelectedPreset] = useState<number | null>(null);
  const [redeeming, setRedeeming] = useState(false);

  const loadData = useCallback(async () => {
    if (!user) return;
    try {
      const [prof, txns] = await Promise.all([
        Users.getById(user.id).catch(() => null),
        Wallet.getTransactions(user.id).catch(() => []),
      ]);
      setProfile(prof);
      setWalletCoins(prof?.walletCoins || 0);
      const coinTxns = txns.filter(
        (t) => t.type === "referral_reward" || t.type === "bonus" || t.type === "redemption"
      );
      setTransactions(coinTxns);
    } catch {} finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => { loadData(); }, [loadData]);

  const onRefresh = useCallback(async () => {
    setRefreshing(true);
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    await loadData();
    setRefreshing(false);
  }, [loadData]);

  if (isLoading || !isAuthenticated) return null;

  const referralCode = profile?.referralCode || "";
  const rupeeEquivalent = (walletCoins / 100) * 10;

  async function handleCopyCode() {
    if (!referralCode) return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    await Clipboard.setStringAsync(referralCode);
    setCodeCopied(true);
    setTimeout(() => setCodeCopied(false), 2000);
  }

  const referralLink = referralCode ? `https://idigitalzone.app/invite/${referralCode}` : "";

  async function handleCopyLink() {
    if (!referralLink) return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    await Clipboard.setStringAsync(referralLink);
    setCodeCopied(true);
    setTimeout(() => setCodeCopied(false), 2000);
  }

  async function handleShare() {
    if (!referralCode) return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    try {
      await Share.share({
        message: `Hey! Join iDigitalZone using my referral code ${referralCode} and we both earn reward coins when you make your first purchase!\n\n${referralLink}`,
      });
    } catch {}
  }

  function handlePresetTap(amount: number) {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    setSelectedPreset(amount);
    setRedeemAmount(String(amount));
  }

  function handleRedeemAmountChange(text: string) {
    const cleaned = text.replace(/[^0-9]/g, "");
    setRedeemAmount(cleaned);
    const num = parseInt(cleaned, 10);
    if (REDEEM_PRESETS.includes(num)) {
      setSelectedPreset(num);
    } else {
      setSelectedPreset(null);
    }
  }

  async function handleRedeem() {
    const coins = parseInt(redeemAmount, 10);
    if (isNaN(coins) || coins <= 0) return;
    if (!user) return;

    setRedeeming(true);
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    try {
      const result = await Wallet.redeemCoins(user.id, coins);
      if (result.success) {
        Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
        Alert.alert("Redeemed!", result.message);
        setRedeemVisible(false);
        setRedeemAmount("");
        setSelectedPreset(null);
        await loadData();
      } else {
        Alert.alert("Cannot Redeem", result.message);
      }
    } catch {
      Alert.alert("Error", "Something went wrong. Please try again.");
    } finally {
      setRedeeming(false);
    }
  }

  function formatTxnDate(iso: string) {
    const d = new Date(iso);
    const now = new Date();
    const diff = now.getTime() - d.getTime();
    if (diff < 60000) return "Just now";
    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
    return d.toLocaleDateString("en-IN", { day: "numeric", month: "short", year: d.getFullYear() !== now.getFullYear() ? "numeric" : undefined });
  }

  const redeemCoinsNum = parseInt(redeemAmount, 10) || 0;
  const redeemValid = redeemCoinsNum >= 100 && redeemCoinsNum % 100 === 0 && redeemCoinsNum <= walletCoins;

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <View style={[styles.header, { paddingTop: topPadding + 8, backgroundColor: colors.background, borderBottomColor: colors.border }]}>
        <Pressable onPress={() => router.back()} hitSlop={12} style={styles.backBtn}>
          <Ionicons name="arrow-back" size={22} color={colors.text} />
        </Pressable>
        <Text style={[styles.headerTitle, { color: colors.text }]}>Invite & Earn</Text>
        <View style={{ width: 22 }} />
      </View>

      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.tint} colors={[colors.tint]} progressBackgroundColor={colors.card} />
        }
      >
        <LinearGradient
          colors={isDark ? ["#4C1D95", "#6D28D9"] : ["#7C3AED", "#A855F7"]}
          start={{ x: 0, y: 0 }}
          end={{ x: 1, y: 1 }}
          style={styles.heroBanner}
        >
          <View style={styles.heroDecor}>
            <View style={[styles.heroCircle, styles.heroCircle1]} />
            <View style={[styles.heroCircle, styles.heroCircle2]} />
            <View style={[styles.heroCircle, styles.heroCircle3]} />
          </View>
          <View style={styles.heroContent}>
            <View style={styles.heroIconWrap}>
              <Ionicons name="gift" size={32} color="#FFF" />
            </View>
            <Text style={styles.heroTitle}>Invite Friends, Earn Coins!</Text>
            <Text style={styles.heroSubtitle}>
              Share your referral code with friends. When they make their first purchase, you both earn reward coins!
            </Text>
          </View>
        </LinearGradient>

        {loading ? (
          <ActivityIndicator size="large" color={colors.tint} style={{ marginVertical: 40 }} />
        ) : (
          <>
            <View style={[styles.codeCard, { backgroundColor: colors.card, borderColor: colors.border }]}>
              <Text style={[styles.codeLabel, { color: colors.textSecondary }]}>Your Referral Code</Text>
              <View style={styles.codeRow}>
                <View style={[styles.codeBox, { backgroundColor: isDark ? "#1E293B" : "#F1F5F9", borderColor: colors.border }]}>
                  <Text style={[styles.codeText, { color: colors.text }]}>{referralCode || "—"}</Text>
                </View>
                <Pressable
                  style={[styles.copyBtn, { backgroundColor: codeCopied ? "#22C55E" : colors.tint }]}
                  onPress={handleCopyCode}
                  disabled={!referralCode}
                >
                  <Ionicons name={codeCopied ? "checkmark" : "copy-outline"} size={18} color="#FFF" />
                </Pressable>
              </View>

              <Text style={[styles.codeLabel, { color: colors.textSecondary, marginTop: 14 }]}>Your Referral Link</Text>
              <Pressable
                style={[styles.linkRow, { backgroundColor: isDark ? "#1E293B" : "#F1F5F9", borderColor: colors.border }]}
                onPress={handleCopyLink}
                disabled={!referralLink}
              >
                <Ionicons name="link-outline" size={16} color={colors.textSecondary} />
                <Text style={[styles.linkText, { color: colors.textSecondary }]} numberOfLines={1} ellipsizeMode="middle">
                  {referralLink || "—"}
                </Text>
                <Ionicons name={codeCopied ? "checkmark-circle" : "copy-outline"} size={16} color={codeCopied ? "#22C55E" : colors.tint} />
              </Pressable>

              <Pressable
                style={({ pressed }) => [styles.shareBtn, { backgroundColor: isDark ? "#4C1D95" : "#7C3AED", opacity: pressed ? 0.85 : 1 }]}
                onPress={handleShare}
                disabled={!referralCode}
              >
                <Ionicons name="share-social-outline" size={18} color="#FFF" />
                <Text style={styles.shareBtnText}>Share with Friends</Text>
              </Pressable>
            </View>

            <View style={[styles.coinCard, { backgroundColor: isDark ? "#1E293B" : "#FFFBEB", borderColor: isDark ? "#F59E0B30" : "#F59E0B40" }]}>
              <View style={styles.coinCardTop}>
                <View style={styles.coinCardLeft}>
                  <View style={[styles.coinIconWrap, { backgroundColor: "#F59E0B20" }]}>
                    <Ionicons name="logo-bitcoin" size={24} color="#F59E0B" />
                  </View>
                  <View>
                    <Text style={[styles.coinCardLabel, { color: colors.textSecondary }]}>Your Coins</Text>
                    <Text style={[styles.coinCardValue, { color: colors.text }]}>{walletCoins.toLocaleString()}</Text>
                    <Text style={[styles.coinCardSub, { color: colors.textSecondary }]}>
                      Worth {"\u20B9"}{rupeeEquivalent.toFixed(0)}
                    </Text>
                  </View>
                </View>
                <Pressable
                  style={({ pressed }) => [
                    styles.redeemBtn,
                    {
                      backgroundColor: walletCoins >= 100 ? "#F59E0B" : isDark ? "#374151" : "#E5E7EB",
                      opacity: pressed && walletCoins >= 100 ? 0.85 : 1,
                    },
                  ]}
                  onPress={() => {
                    if (walletCoins >= 100) {
                      Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
                      setRedeemVisible(true);
                    } else {
                      Alert.alert("Not Enough Coins", "You need at least 100 coins to redeem. Invite friends to earn more!");
                    }
                  }}
                >
                  <Ionicons name="swap-horizontal" size={16} color={walletCoins >= 100 ? "#FFF" : colors.textSecondary} />
                  <Text style={[styles.redeemBtnText, { color: walletCoins >= 100 ? "#FFF" : colors.textSecondary }]}>Redeem</Text>
                </Pressable>
              </View>
              <View style={[styles.coinInfoRow, { borderTopColor: isDark ? "#F59E0B20" : "#F59E0B30" }]}>
                <Ionicons name="information-circle-outline" size={14} color={colors.textSecondary} />
                <Text style={[styles.coinInfoText, { color: colors.textSecondary }]}>100 coins = {"\u20B9"}10 (added to your wallet balance)</Text>
              </View>
            </View>

            <View style={styles.howItWorksSection}>
              <Text style={[styles.sectionTitle, { color: colors.text }]}>How It Works</Text>
              <View style={styles.stepsRow}>
                {[
                  { icon: "share-social" as const, label: "Share Code", desc: "Send your code to friends", color: "#8B5CF6" },
                  { icon: "person-add" as const, label: "Friend Joins", desc: "They sign up & purchase", color: "#3B82F6" },
                  { icon: "gift" as const, label: "Earn Coins", desc: "Both of you earn coins", color: "#F59E0B" },
                ].map((step, i) => (
                  <View key={step.label} style={[styles.stepCard, { backgroundColor: colors.card, borderColor: colors.border }]}>
                    <View style={[styles.stepIconWrap, { backgroundColor: step.color + "15" }]}>
                      <Ionicons name={step.icon} size={20} color={step.color} />
                    </View>
                    <Text style={[styles.stepLabel, { color: colors.text }]}>{step.label}</Text>
                    <Text style={[styles.stepDesc, { color: colors.textSecondary }]}>{step.desc}</Text>
                    {i < 2 && (
                      <View style={styles.stepArrow}>
                        <Ionicons name="chevron-forward" size={14} color={colors.textSecondary} />
                      </View>
                    )}
                  </View>
                ))}
              </View>
            </View>

            <View style={styles.txnSection}>
              <Text style={[styles.sectionTitle, { color: colors.text }]}>Coin Activity</Text>
              {transactions.length === 0 ? (
                <View style={styles.emptyState}>
                  <View style={[styles.emptyIcon, { backgroundColor: isDark ? "#1E293B" : "#F1F5F9" }]}>
                    <Ionicons name="gift-outline" size={32} color={colors.textSecondary} />
                  </View>
                  <Text style={[styles.emptyTitle, { color: colors.textSecondary }]}>No coin activity yet</Text>
                  <Text style={[styles.emptyDesc, { color: colors.textSecondary }]}>Invite friends to start earning coins!</Text>
                </View>
              ) : (
                transactions.map((txn, i) => (
                  <View key={txn.id}>
                    {i > 0 && <View style={[styles.txnSep, { backgroundColor: colors.border }]} />}
                    <View style={styles.txnRow}>
                      <View style={[styles.txnIcon, { backgroundColor: txn.type === "redemption" ? "#3B82F610" : "#F59E0B10" }]}>
                        <Ionicons
                          name={txn.type === "redemption" ? "swap-horizontal" : "gift"}
                          size={16}
                          color={txn.type === "redemption" ? "#3B82F6" : "#F59E0B"}
                        />
                      </View>
                      <View style={styles.txnInfo}>
                        <Text style={[styles.txnDesc, { color: colors.text }]} numberOfLines={1}>{txn.description}</Text>
                        <Text style={[styles.txnDate, { color: colors.textSecondary }]}>{formatTxnDate(txn.createdAt)}</Text>
                      </View>
                      <View style={styles.txnRight}>
                        <Text style={[styles.txnAmount, { color: txn.coins > 0 ? "#10B981" : "#EF4444" }]}>
                          {txn.coins > 0 ? "+" : ""}{txn.coins}
                        </Text>
                        <Text style={[styles.txnCoinLabel, { color: colors.textSecondary }]}>coins</Text>
                      </View>
                    </View>
                  </View>
                ))
              )}
            </View>

            <View style={{ height: 40 }} />
          </>
        )}
      </ScrollView>

      <Modal visible={redeemVisible} transparent animationType="fade" onRequestClose={() => setRedeemVisible(false)}>
        <Pressable style={styles.modalOverlay} onPress={() => { Keyboard.dismiss(); setRedeemVisible(false); }}>
          <KeyboardAvoidingView behavior={Platform.OS === "ios" ? "padding" : "height"} style={styles.modalKAV}>
            <Pressable style={[styles.modalBox, { backgroundColor: colors.card }]} onPress={(e) => e.stopPropagation()}>
              <View style={[styles.modalHandle, { backgroundColor: colors.border }]} />
              <Text style={[styles.modalTitle, { color: colors.text }]}>Redeem Coins</Text>
              <Text style={[styles.modalSubtitle, { color: colors.textSecondary }]}>
                Available: {walletCoins.toLocaleString()} coins
              </Text>

              <View style={styles.presetGrid}>
                {REDEEM_PRESETS.filter((p) => p <= walletCoins).map((amt) => (
                  <Pressable
                    key={amt}
                    style={[
                      styles.presetChip,
                      {
                        backgroundColor: selectedPreset === amt ? "#F59E0B15" : isDark ? "#1E293B" : "#F1F5F9",
                        borderColor: selectedPreset === amt ? "#F59E0B" : colors.border,
                      },
                    ]}
                    onPress={() => handlePresetTap(amt)}
                  >
                    <Text style={[styles.presetText, { color: selectedPreset === amt ? "#F59E0B" : colors.text }]}>
                      {amt}
                    </Text>
                    <Text style={[styles.presetSub, { color: colors.textSecondary }]}>
                      = {"\u20B9"}{(amt / 100) * 10}
                    </Text>
                  </Pressable>
                ))}
              </View>

              <View style={[styles.customInputWrap, { backgroundColor: isDark ? "#1E293B" : "#F1F5F9", borderColor: colors.border }]}>
                <Ionicons name="logo-bitcoin" size={18} color={colors.textSecondary} />
                <TextInput
                  style={[styles.customInput, { color: colors.text }]}
                  placeholder="Enter coins (multiples of 100)"
                  placeholderTextColor={colors.textSecondary}
                  keyboardType="number-pad"
                  value={redeemAmount}
                  onChangeText={handleRedeemAmountChange}
                  returnKeyType="done"
                  onSubmitEditing={() => Keyboard.dismiss()}
                />
              </View>

              {redeemCoinsNum > 0 && (
                <View style={[styles.redeemPreview, { backgroundColor: isDark ? "#06492430" : "#ECFDF5", borderColor: isDark ? "#10B98130" : "#10B98140" }]}>
                  <Text style={[styles.redeemPreviewText, { color: "#10B981" }]}>
                    You'll receive {"\u20B9"}{((redeemCoinsNum / 100) * 10).toFixed(0)} in your wallet
                  </Text>
                </View>
              )}

              {redeemCoinsNum > 0 && redeemCoinsNum % 100 !== 0 && (
                <Text style={[styles.errorHint, { color: "#EF4444" }]}>Must be in multiples of 100</Text>
              )}
              {redeemCoinsNum > walletCoins && (
                <Text style={[styles.errorHint, { color: "#EF4444" }]}>Not enough coins</Text>
              )}

              <Pressable
                style={({ pressed }) => [
                  styles.redeemConfirmBtn,
                  {
                    backgroundColor: redeemValid ? "#F59E0B" : isDark ? "#374151" : "#D1D5DB",
                    opacity: pressed && redeemValid ? 0.85 : 1,
                  },
                ]}
                onPress={handleRedeem}
                disabled={!redeemValid || redeeming}
              >
                {redeeming ? (
                  <ActivityIndicator size="small" color="#FFF" />
                ) : (
                  <Text style={[styles.redeemConfirmText, { color: redeemValid ? "#FFF" : colors.textSecondary }]}>
                    {redeemValid ? `Redeem ${redeemCoinsNum} Coins` : "Select coins to redeem"}
                  </Text>
                )}
              </Pressable>
            </Pressable>
          </KeyboardAvoidingView>
        </Pressable>
      </Modal>
    </View>
  );
}

const styles = StyleSheet.create({
