  errorHint: { fontSize: 12, fontFamily: "Inter_400Regular", marginBottom: 8 },

  redeemConfirmBtn: { alignItems: "center", paddingVertical: 16, borderRadius: 14 },
  redeemConfirmText: { fontSize: 15, fontFamily: "Inter_600SemiBold" },
