function genId() {
  return Date.now().toString() + Math.random().toString(36).substr(2, 9);
}

function genShortId(prefix: string = "NX") {
  const chars = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789";
  let result = prefix;
  for (let i = 0; i < 8; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
}

