import React, { useState, useEffect, useCallback, useRef } from "react";
import {
  StyleSheet,
  Text,
  View,
  ScrollView,
  Pressable,
  Platform,
  ActivityIndicator,
  TextInput,
  Keyboard,
  KeyboardAvoidingView,
  RefreshControl,
  Alert,
} from "react-native";
import { router, useFocusEffect } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { Ionicons } from "@expo/vector-icons";
import * as Haptics from "expo-haptics";
import { useAuth } from "@/lib/auth-context";
import { useTheme } from "@/lib/useTheme";
import { Users, Wallet, WalletOrders } from "@/lib/firestore";
import type { WalletTransaction, WalletOrder } from "@/lib/firestore";

const PRESETS = [100, 200, 500, 1000];

export default function WalletScreen() {
  const { colors, isDark } = useTheme();
  const insets = useSafeAreaInsets();
  const { user, isAuthenticated, isLoading } = useAuth();
  const topPadding = Platform.OS === "web" ? 67 : insets.top;

  const [walletBalance, setWalletBalance] = useState(0);
  const [transactions, setTransactions] = useState<WalletTransaction[]>([]);
  const [pendingOrders, setPendingOrders] = useState<WalletOrder[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [addMoneyVisible, setAddMoneyVisible] = useState(false);
  const [selectedPreset, setSelectedPreset] = useState<number | null>(null);
  const [customAmount, setCustomAmount] = useState("");

  const inputRef = useRef<TextInput>(null);

  const loadWalletData = useCallback(async () => {
    if (!user) return;
    try {
      const [prof, txns, wOrders] = await Promise.all([
        Users.getById(user.id).catch(() => null),
        Wallet.getTransactions(user.id).catch(() => []),
        WalletOrders.getByUser(user.id).catch(() => []),
      ]);
      setWalletBalance(prof?.walletBalance || 0);
      setTransactions(txns);
      setPendingOrders(wOrders.filter((o) => o.status !== "paid"));
    } catch {} finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => { loadWalletData(); }, [loadWalletData]);

  useFocusEffect(
    useCallback(() => {
      loadWalletData();
    }, [loadWalletData])
  );

  const onRefresh = useCallback(async () => {
    setRefreshing(true);
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    await loadWalletData();
    setRefreshing(false);
  }, [loadWalletData]);

  if (isLoading || !isAuthenticated) return null;

  const rupeeBalance = walletBalance.toFixed(2);
  const payAmount = parseInt(customAmount, 10) || 0;

  function handlePresetTap(amount: number) {
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
    setSelectedPreset(amount);
    setCustomAmount(String(amount));
  }

  function handleCustomChange(text: string) {
    const cleaned = text.replace(/[^0-9]/g, "");
    setCustomAmount(cleaned);
    const num = parseInt(cleaned, 10);
    if (PRESETS.includes(num)) {
      setSelectedPreset(num);
    } else {
      setSelectedPreset(null);
    }
  }

  function handleCancelOrder(order: WalletOrder) {
    Alert.alert(
      "Cancel Request",
      `Cancel this \u20B9${order.amount} add money request?`,
      [
        { text: "No", style: "cancel" },
        {
          text: "Yes, Cancel",
          style: "destructive",
          onPress: async () => {
            try {
              await WalletOrders.delete(order.id);
              Haptics.notificationAsync(Haptics.NotificationFeedbackType.Success);
              await loadWalletData();
            } catch {
              Alert.alert("Error", "Failed to cancel request. Please try again.");
            }
          },
        },
      ]
    );
  }

  function handleProceedPay() {
    if (payAmount <= 0) return;
    Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium);
    Keyboard.dismiss();
    setAddMoneyVisible(false);
    setSelectedPreset(null);
    setCustomAmount("");
    router.push({ pathname: "/upi-payment", params: { amount: String(payAmount) } });
  }

  function handleCloseSheet() {
    Keyboard.dismiss();
    setAddMoneyVisible(false);
    setSelectedPreset(null);
    setCustomAmount("");
  }

  function formatTxnDate(iso: string) {
    const d = new Date(iso);
    const now = new Date();
    const diff = now.getTime() - d.getTime();
    if (diff < 60000) return "Just now";
    if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
    if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
    return d.toLocaleDateString("en-IN", { day: "numeric", month: "short", year: d.getFullYear() !== now.getFullYear() ? "numeric" : undefined });
  }

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <View style={[styles.header, { paddingTop: topPadding + 8, backgroundColor: colors.background, borderBottomColor: colors.border }]}>
        <Pressable onPress={() => router.back()} hitSlop={12} style={styles.backBtn}>
          <Ionicons name="arrow-back" size={22} color={colors.text} />
        </Pressable>
        <Text style={[styles.headerTitle, { color: colors.text }]}>Wallet</Text>
        <View style={{ width: 22 }} />
      </View>

      <ScrollView
        contentContainerStyle={styles.scroll}
        showsVerticalScrollIndicator={false}
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={onRefresh}
            tintColor={colors.tint}
            colors={[colors.tint]}
            progressBackgroundColor={colors.card}
          />
        }
      >
        <View style={[styles.balanceCard, { backgroundColor: isDark ? "#1E293B" : "#F8FAFC", borderColor: colors.border }]}>
          <Text style={[styles.balanceLabel, { color: colors.textSecondary }]}>Total Balance</Text>
          {loading ? (
            <ActivityIndicator size="large" color={colors.tint} style={{ marginVertical: 12 }} />
          ) : (
            <Text style={[styles.balanceAmount, { color: colors.text }]}>{"\u20B9"}{rupeeBalance}</Text>
          )}
        </View>

        <View style={styles.actionRow}>
          <Pressable
            style={({ pressed }) => [styles.actionBtn, { backgroundColor: colors.tint, opacity: pressed ? 0.85 : 1 }]}
            onPress={() => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); setAddMoneyVisible(true); }}
          >
            <Ionicons name="add-circle-outline" size={20} color="#FFF" />
            <Text style={styles.actionBtnText}>Add Money</Text>
          </Pressable>
          <Pressable
            style={({ pressed }) => [styles.actionBtn, { backgroundColor: "#EF4444", opacity: pressed ? 0.85 : 1 }]}
            onPress={() => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); router.push("/withdraw"); }}
          >
            <Ionicons name="arrow-up-circle-outline" size={20} color="#FFF" />
            <Text style={styles.actionBtnText}>Withdraw</Text>
          </Pressable>
        </View>

        <Pressable
          style={({ pressed }) => [styles.inviteBar, { backgroundColor: isDark ? "#4C1D95" : "#7C3AED", opacity: pressed ? 0.9 : 1 }]}
          onPress={() => { Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Medium); router.push("/invite-earn"); }}
        >
          <View style={styles.inviteBarLeft}>
            <View style={[styles.inviteIconWrap, { backgroundColor: "rgba(255,255,255,0.2)" }]}>
              <Ionicons name="gift" size={18} color="#FFF" />
            </View>
            <View>
              <Text style={styles.inviteBarTitle}>Invite & Earn Coins</Text>
              <Text style={styles.inviteBarSub}>Share your code & earn rewards</Text>
            </View>
          </View>
          <Ionicons name="chevron-forward" size={18} color="rgba(255,255,255,0.7)" />
        </Pressable>

        <View style={[styles.futureRow]}>
          {[
            { icon: "flash-outline" as const, label: "Cashback", color: "#F59E0B" },
            { icon: "trophy-outline" as const, label: "Rewards", color: "#8B5CF6" },
            { icon: "time-outline" as const, label: "History", color: colors.tint },
          ].map((item) => (
            <Pressable key={item.label} style={[styles.futureItem, { backgroundColor: colors.card, borderColor: colors.border }]}>
              <Ionicons name={item.icon} size={20} color={item.color} />
              <Text style={[styles.futureLabel, { color: colors.textSecondary }]}>{item.label}</Text>
            </Pressable>
          ))}
        </View>

        {pendingOrders.length > 0 && (
          <View style={styles.txnSection}>
            <Text style={[styles.txnSectionTitle, { color: colors.text }]}>Add Money Requests</Text>
            {pendingOrders.map((order) => {
              const statusConfig: Record<string, { label: string; color: string; bg: string; icon: string }> = {
                pending: { label: "Pending", color: "#6B7280", bg: "rgba(107,114,128,0.12)", icon: "time-outline" },
                verification_pending: { label: "Verifying", color: "#F59E0B", bg: "rgba(245,158,11,0.12)", icon: "hourglass-outline" },
                rejected: { label: "Rejected", color: "#EF4444", bg: "rgba(239,68,68,0.12)", icon: "close-circle-outline" },
              };
              const st = statusConfig[order.status] || statusConfig.pending;
              const handleCardPress = () => {
                Haptics.impactAsync(Haptics.ImpactFeedbackStyle.Light);
                if (order.status === "pending") {
                  router.push({ pathname: "/upi-payment", params: { amount: String(order.amount), orderId: order.id } });
                } else if (order.status === "verification_pending") {
                  router.push({ pathname: "/upi-payment", params: { amount: String(order.amount), orderId: order.id, mode: "waiting" } });
                }
              };
              const isClickable = order.status === "pending" || order.status === "verification_pending";
              return (
                <Pressable
                  key={order.id}
                  style={({ pressed }) => [styles.pendingCard, { backgroundColor: colors.card, borderColor: colors.border, opacity: pressed && isClickable ? 0.8 : 1 }]}
                  onPress={isClickable ? handleCardPress : undefined}
                >
                  <View style={styles.pendingCardTop}>
                    <View style={[styles.pendingIcon, { backgroundColor: st.bg }]}>
                      <Ionicons name={st.icon as any} size={18} color={st.color} />
                    </View>
                    <View style={{ flex: 1 }}>
                      <Text style={[styles.pendingAmount, { color: colors.text }]}>{"\u20B9"}{order.amount}</Text>
                      <Text style={[styles.pendingOrderId, { color: colors.textSecondary }]}>{order.orderId}</Text>
                    </View>
                    <View style={[styles.pendingBadge, { backgroundColor: st.bg }]}>
                      <Text style={[styles.pendingBadgeText, { color: st.color }]}>{st.label}</Text>
                    </View>
                    {isClickable && <Ionicons name="chevron-forward" size={16} color={colors.textSecondary} />}
                  </View>
                  {order.utr ? (
                    <Text style={[styles.pendingUtr, { color: colors.textSecondary }]}>UTR: {order.utr}</Text>
                  ) : null}
                  <Text style={[styles.pendingDate, { color: colors.textSecondary }]}>
                    {formatTxnDate(order.createdAt)}
                    {order.status === "pending" ? "  \u2022  Tap to submit UTR" : ""}
                    {order.status === "verification_pending" ? "  \u2022  Tap to view status" : ""}
                  </Text>
                  {order.status === "pending" && (
                    <Pressable
                      style={[styles.cancelBtn, { backgroundColor: isDark ? "rgba(239,68,68,0.1)" : "rgba(239,68,68,0.08)" }]}
                      onPress={(e) => {
                        e.stopPropagation();
                        handleCancelOrder(order);
                      }}
                      hitSlop={6}
                    >
                      <Ionicons name="trash-outline" size={14} color="#EF4444" />
                      <Text style={styles.cancelBtnText}>Cancel Request</Text>
                    </Pressable>
                  )}
                </Pressable>
              );
            })}
          </View>
        )}

        <View style={styles.txnSection}>
          <Text style={[styles.txnSectionTitle, { color: colors.text }]}>Recent Transactions</Text>

          {loading ? (
            <ActivityIndicator size="small" color={colors.tint} style={{ marginTop: 20 }} />
          ) : transactions.length === 0 ? (
            <View style={styles.emptyState}>
              <View style={[styles.emptyIcon, { backgroundColor: isDark ? "#1E293B" : "#F1F5F9" }]}>
                <Ionicons name="receipt-outline" size={32} color={colors.textSecondary} />
              </View>
              <Text style={[styles.emptyTitle, { color: colors.textSecondary }]}>No transactions yet</Text>
              <Text style={[styles.emptyDesc, { color: colors.textSecondary }]}>Your transaction history will appear here</Text>
            </View>
          ) : (
            transactions.map((txn, i) => {
              const rupeeAmt = txn.amountRupees != null ? txn.amountRupees : (txn.coins > 0 ? (txn.coins / 100) * 10 : -((Math.abs(txn.coins) / 100) * 10));
              const isPositive = rupeeAmt > 0 || (txn.type === "admin_credit" || txn.type === "referral_reward" || txn.type === "bonus");
              const displayAmt = txn.amountRupees != null ? rupeeAmt : Math.abs(rupeeAmt) * (isPositive ? 1 : -1);
              return (
                <View key={txn.id}>
                  {i > 0 && <View style={[styles.txnSep, { backgroundColor: colors.border }]} />}
                  <View style={styles.txnRow}>
                    <View style={[styles.txnIcon, { backgroundColor: isPositive ? "#10B98110" : "#EF444410" }]}>
                      <Ionicons
                        name={isPositive ? "arrow-down" : "arrow-up"}
                        size={16}
                        color={isPositive ? "#10B981" : "#EF4444"}
                      />
                    </View>
                    <View style={styles.txnInfo}>
                      <Text style={[styles.txnDesc, { color: colors.text }]} numberOfLines={1}>{txn.description}</Text>
                      <Text style={[styles.txnDate, { color: colors.textSecondary }]}>{formatTxnDate(txn.createdAt)}</Text>
                    </View>
                    <View style={styles.txnRight}>
                      <Text style={[styles.txnAmount, { color: isPositive ? "#10B981" : "#EF4444" }]}>
                        {isPositive ? "+" : "-"}{"\u20B9"}{Math.abs(displayAmt).toFixed(0)}
                      </Text>
                    </View>
                  </View>
                </View>
              );
            })
          )}
        </View>

        <View style={{ height: 40 }} />
      </ScrollView>

      {addMoneyVisible && (
        <View style={StyleSheet.absoluteFill} pointerEvents="box-none">
          <Pressable style={styles.sheetBackdrop} onPress={handleCloseSheet} />
          <KeyboardAvoidingView
            style={styles.sheetKAV}
            behavior={Platform.OS === "ios" ? "padding" : "height"}
            keyboardVerticalOffset={0}
          >
            <View
              style={[
                styles.sheetBox,
                {
                  backgroundColor: colors.card,
                  paddingBottom: Math.max(insets.bottom, 16),
                },
              ]}
            >
              <View style={[styles.sheetHandle, { backgroundColor: colors.border }]} />

              <ScrollView
                bounces={false}
                showsVerticalScrollIndicator={false}
                keyboardShouldPersistTaps="handled"
                contentContainerStyle={styles.sheetContent}
              >
                <Text style={[styles.sheetTitle, { color: colors.text }]}>Add Money to Wallet</Text>

                <View style={styles.presetGrid}>
                  {PRESETS.map((amt) => (
                    <Pressable
                      key={amt}
                      style={[
                        styles.presetChip,
                        {
                          backgroundColor: selectedPreset === amt ? colors.tint + "15" : isDark ? "#1E293B" : "#F1F5F9",
                          borderColor: selectedPreset === amt ? colors.tint : colors.border,
                        },
                      ]}
                      onPress={() => handlePresetTap(amt)}
                    >
                      <Text style={[styles.presetText, { color: selectedPreset === amt ? colors.tint : colors.text }]}>
                        {"\u20B9"}{amt}
                      </Text>
                    </Pressable>
                  ))}
                </View>

                <Pressable
                  style={[styles.customInputWrap, { backgroundColor: isDark ? "#1E293B" : "#F1F5F9", borderColor: colors.border }]}
                  onPress={() => inputRef.current?.focus()}
                >
                  <Text style={[styles.customPrefix, { color: colors.textSecondary }]}>{"\u20B9"}</Text>
                  <TextInput
                    ref={inputRef}
                    style={[styles.customInput, { color: colors.text }]}
                    placeholder="Enter custom amount"
                    placeholderTextColor={colors.textSecondary}
                    keyboardType="number-pad"
                    value={customAmount}
                    onChangeText={handleCustomChange}
                    returnKeyType="done"
                    onSubmitEditing={() => Keyboard.dismiss()}
                  />
                </Pressable>

                <Pressable
                  style={({ pressed }) => [
                    styles.proceedBtn,
                    {
                      backgroundColor: payAmount > 0 ? colors.tint : isDark ? "#374151" : "#D1D5DB",
                      opacity: pressed && payAmount > 0 ? 0.85 : 1,
                    },
                  ]}
                  onPress={handleProceedPay}
                  disabled={payAmount <= 0}
                >
                  <Text style={[styles.proceedText, { color: payAmount > 0 ? "#FFF" : colors.textSecondary }]}>
                    {payAmount > 0 ? `Proceed to Pay \u20B9${payAmount}` : "Select an amount"}
                  </Text>
                </Pressable>
              </ScrollView>
            </View>
          </KeyboardAvoidingView>
        </View>
      )}
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  header: {
