                            name={isExclusive ? "diamond" : "checkmark-circle"}
                            size={14}
                            color={isExclusive ? "#F59E0B" : "#10B981"}
                          />
                          <Text style={[
                            styles.planFeatureText,
                            { color: isExclusive ? "#F59E0B" : colors.textSecondary },
                            isExclusive && { fontFamily: "Inter_600SemiBold" },
                          ]}>{f}</Text>
